function norm(s) {
  return (s||"").toLowerCase().trim().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/\s+/g," ");
}

function mergeComites(comitesSupa=[]) {
  const base = COMITES_DATA.map(c=>({...c}));
  const nombresBase = new Set(base.map(c=>norm(c.nombre)));
  let nextR=base.filter(c=>c.tipo==="Rural").length+1;
  let nextU=base.filter(c=>c.tipo==="Urbano").length+1;
  comitesSupa.forEach(sc=>{
    if(!sc.nombre||!sc.nombre.trim()) return;
    if(nombresBase.has(norm(sc.nombre))) return;
    const esU=sc.programaId==="csp_urbano"||sc.nombre.toUpperCase().includes("URBANO");
    const tipo=esU?"Urbano":"Rural";
    const codigo=esU?`gr${nextU}U`:`gr${nextR}R`;
    if(esU) nextU++; else nextR++;
    base.push({id:sc.id,codigo,nombre:sc.nombre,familias:0,tipo,constructora:sc.descripcion||"ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â",profesional:"ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â",pj:"ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â",venc:"ÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¢ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡Ãƒâ€šÃ‚Â¬ÃƒÆ’Ã‚Â¢ÃƒÂ¢Ã¢â‚¬Å¡Ã‚Â¬Ãƒâ€šÃ‚Â",directiva:[]});
    nombresBase.add(norm(sc.nombre));
  });
  return base;
}

function miembrosComite(comite, personas) {
  return personas.filter(p=>
    p.comiteId===comite.codigo||p.comiteId===comite.id||
    (p.comite&&norm(p.comite)===norm(comite.nombre))
  );
}

function solPersona(persona, solicitudes) {
  return solicitudes.filter(s=>s.personaId===persona.id||s.persona_id===persona.id);
}

function rutKey(rut) {
  return (rut||"").toLowerCase().replace(/[^0-9k]/g,"");
}

function personasRelacionadas(persona, personas=[]) {
  const rk = rutKey(persona.rut);
  const nk = norm(persona.nombre);
  return personas.filter(p => {
    if (rk && rutKey(p.rut) === rk) return true;
    return !rk && nk && norm(p.nombre) === nk;
  });
}

function solPersonasRelacionadas(persona, solicitudes, personas=[]) {
  const ids = new Set(personasRelacionadas(persona, personas).map(p=>p.id));
  if (ids.size === 0) ids.add(persona.id);
  return solicitudes.filter(s=>ids.has(s.personaId)||ids.has(s.persona_id));
}

function programaId(sol) {
  return sol.programaId || sol.programa_id || "";
}

function programaNombre(id) {
  const nombres = {
    habitabilidad: "Habitabilidad de Vivienda (Desmarque de Vivienda)",
    csp_rural: "ConstrucciÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â³n Sitio Propio Rural",
    csp_urbano: "ConstrucciÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â³n Sitio Propio Urbano",
  };
  return nombres[id] || id || "Programa";
}

function programasDisponiblesPersona(persona, solicitudes, personas=[]) {
  const relacionadas = personasRelacionadas(persona, personas);
  const basePersonas = relacionadas.length ? relacionadas : [persona];
  const ids = new Set(solPersonasRelacionadas(persona, solicitudes, personas).map(programaId).filter(Boolean));
  basePersonas.forEach(p => {
    if (p.comiteId === "comite_desmarque") ids.add("habitabilidad");
    const texto = `${p.tipo_comite || ""} ${p.tipoComite || ""} ${p.comite || ""}`.toUpperCase();
    if (texto.includes("RURAL")) ids.add("csp_rural");
    if (texto.includes("URBANO")) ids.add("csp_urbano");
  });
  return [...ids].map(id => ({ id, nombre: programaNombre(id) }));
}

function calcularEdad(fechaNac) {
  if(!fechaNac) return null;
  const hoyD=new Date(), nac=new Date(fechaNac);
  if(isNaN(nac)) return null;
  let e=hoyD.getFullYear()-nac.getFullYear();
  const m=hoyD.getMonth()-nac.getMonth();
  if(m<0||(m===0&&hoyD.getDate()<nac.getDate())) e--;
  return e;
}

function hoy() {
  return new Date().toLocaleDateString("es-CL",{day:"2-digit",month:"2-digit",year:"numeric"});
}

