            const programas = programasDisponiblesPersona(p, solicitudes);
            const solsInforme = programaSeleccionado === "todos" ? sols : sols.filter(s=>programaId(s)===programaSeleccionado);
            const totD = solsInforme.reduce((a,s)=>a+(s.documentos||[]).length,0);
            const okD  = solsInforme.reduce((a,s)=>a+(s.documentos||[]).filter(d=>d.entregado).length,0);
            const faltD = solsInforme.reduce((a,s)=>a+(s.documentos||[]).filter(d=>!d.entregado&&d.obligatorio).length,0);
            const pct = totD>0?Math.round((okD/totD)*100):null;
